import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { CanDeactivateGuard } from 'src/app/shared/guards/can-deactivate.guard';
import { ExcelMappingEditComponent } from './excel-mapping-edit/excel-mapping-edit.component';
import { ExcelMappingNewComponent } from './excel-mapping-new/excel-mapping-new.component';
import { ExcelMappingComponent } from './excel-mapping/excel-mapping.component';

const routes: Routes = [
  {
    path:"",
    component:ExcelMappingComponent
  }, {
    path:"excel-mapping-new",
    component:ExcelMappingNewComponent,
    canDeactivate: [CanDeactivateGuard]
  },
  {
    path:"excel-mapping-edit",
    component:ExcelMappingEditComponent,
    canDeactivate: [CanDeactivateGuard]
  }
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class ExcelMappingRoutingModule { }
